class Solution:
    def maxProfit(self, inventory, orders):
        MOD = 10 ** 9 + 7
        lo, hi = 0, max(inventory)
        def total_above(x):
            return sum(v - x for v in inventory if v > x)
        while lo < hi:
            mid = (lo + hi) // 2
            if total_above(mid) <= orders:
                hi = mid
            else:
                lo = mid + 1
        threshold = lo
        profit = 0
        for v in inventory:
            if v > threshold:
                profit += (v + threshold + 1) * (v - threshold) // 2
        remaining = orders - total_above(threshold)
        profit += remaining * threshold
        return profit % MOD

