var maxProfit = function(inventory, orders) {
    const MOD = 1000000007n;
    const arr = inventory.slice().sort((a, b) => b - a).map(BigInt);
    arr.push(0n);
    let ordersB = BigInt(orders);
    let profit = 0n;
    let width = 0n;
    const n = arr.length;
    for (let i = 0; i < n - 1; i++) {
        width += 1n;
        const cur = arr[i];
        const nxt = arr[i + 1];
        if (cur <= nxt) continue;
        const span = cur - nxt;
        const count = span * width;
        if (ordersB >= count) {
            profit += (cur + nxt + 1n) * span / 2n * width;
            ordersB -= count;
        } else {
            const q = ordersB / width;
            const r = ordersB % width;
            profit += (cur + cur - q + 1n) * q / 2n * width;
            profit += r * (cur - q);
            ordersB = 0n;
            break;
        }
    }
    return Number(profit % MOD);
};
